class Solution:
    def findWords(self, words):
        rows = ['qwertyuiop', 'asdfghjkl', 'zxcvbnm']
        result = []
        for w in words:
            lw = w.lower()
            found = None
            ok = True
            for ch in lw:
                for ri, row in enumerate(rows):
                    if ch in row:
                        if found is None:
                            found = ri
                        elif found != ri:
                            ok = False
                        break
                if not ok:
                    break
            if ok:
                result.append(w)
        return result

