class Solution:
    def findWords(self, words):
        row_of = {}
        rows = ['qwertyuiop', 'asdfghjkl', 'zxcvbnm']
        for i, row in enumerate(rows):
            for ch in row:
                row_of[ch] = i
        result = []
        for w in words:
            ids = {row_of[ch] for ch in w.lower()}
            if len(ids) == 1:
                result.append(w)
        return result

