var findWords = function(words) {
    const rows = ['qwertyuiop', 'asdfghjkl', 'zxcvbnm'];
    const rowOf = {};
    rows.forEach((row, i) => { for (const ch of row) rowOf[ch] = i; });
    const result = [];
    for (const w of words) {
        const ids = new Set();
        for (const ch of w.toLowerCase()) ids.add(rowOf[ch]);
        if (ids.size === 1) result.push(w);
    }
    return result;
};
